    const chatRoomMessage = createChatRoomMessage(response, agentId);

    if (chatRoomMessage) {
      // Send as chat room protocol message
      yield {
        type: "claude_json",
        data: {
          type: "chat_room_message",
          message: chatRoomMessage,
          session_id: request.sessionId,
        },
      };
    }

    // Also send original response format for compatibility
    if (response.type === "text") {
      accumulatedText += response.content || "";
      yield {
        type: "claude_json",
        data: {
          type: "assistant",
          content: response.content,
          model: response.metadata?.model,
        },
      };
    } else if (response.type === "tool_use") {
      const toolUseId = response.toolUseId || makeToolUseId();
      yield {
        type: "claude_json",
        data: {
          type: "assistant",
          message: {
            content: [{
              type: "tool_use",
              id: toolUseId,
              name: response.toolName || "unknown_tool",
              input: response.toolInput || {},
            }],
          },
          session_id: request.sessionId,
        },
      };

      if (response.toolName !== "delegate_task") continue;

      const delegation = getDelegationInput(response.toolInput);
      let result: AgentRunResult;
      if (!delegation) {
        result = { text: "", error: "delegate_task requires string agent_id and instructions" };
      } else if (delegationPath.includes(delegation.agentId) || delegation.agentId === agentId) {
        const error = `Circular delegation detected for agent '${delegation.agentId}'`;
        yield { type: "error", error };
        result = { text: "", error };
      } else if (!globalRegistry.getAgent(delegation.agentId) || !globalRegistry.getProviderForAgent(delegation.agentId)) {
        const error = `Agent '${delegation.agentId}' not found or provider not available`;
        yield { type: "error", error };
        result = { text: "", error };
      } else {
        const child = executeAgentConversation(
          delegation.agentId,
          { ...request, message: delegation.instructions },
          null,
          abortController,
          debugMode,
          [...delegationPath, agentId],
          delegation.instructions,
          true
        );
        let childStep = await child.next();
        while (!childStep.done) {
          yield childStep.value;
          childStep = await child.next();
        }
        result = childStep.value;
      }

      const toolResult: DelegationToolResult = {
        type: "tool_result",
        is_error: !!result.error,
        content: result.error || result.text || "(The delegated agent completed without textual output.)",
        tool_use_id: toolUseId,
      };
      yield toolResultResponse(toolResult, request.sessionId);

      // Re-invoke the delegating agent so it can continue from the result.
      const resumed = executeAgentConversation(
        agentId,
        request,
        null,
        abortController,
        debugMode,
        delegationPath,
        JSON.stringify(toolResult)
      );
      let resumedStep = await resumed.next();
      while (!resumedStep.done) {
        yield resumedStep.value;
        resumedStep = await resumed.next();
      }
      return {
        text: accumulatedText + resumedStep.value.text,
        error: resumedStep.value.error,
      };
    } else if (response.type === "done") {
      return { text: accumulatedText };
    } else if (response.type === "error") {
      if (!suppressProviderErrors) {
        yield { type: "error", error: response.error };
      }
      return { text: accumulatedText, error: response.error || "Agent execution failed" };
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    if (!suppressProviderErrors) {
      yield { type: "error", error: message };
    }
    return { text: accumulatedText, error: message };
  }

  return { text: accumulatedText };
